{
  "schema_version": "0.3",
  "mode": "design",
  "workflow_kind": "dynamic",
  "dependencies": {
    "parallel_units": true,
    "edges": [
      {
        "from": "route_audit_batch",
        "to": "final_report_synthesis",
        "type": "data",
        "reason": "the final report must wait for the full set of route audit result records before fan-in synthesis and reconciliation"
      }
    ],
    "capacity_constraints": []
  },
  "dynamic": {
    "batch": {
      "handle": "route_audit_batch",
      "item_identity_source": "route_launch_snapshot"
    },
    "await": {
      "join": "all",
      "k": null,
      "quorum_basis": null,
      "eligible_identity_source": "route_launch_snapshot",
      "eligible_statuses": [
        "succeeded",
        "failed",
        "cancelled",
        "timed_out"
      ],
      "wake_event": "route_audit_batch_settled"
    },
    "accounting": {
      "expected_identity_source": "route_launch_snapshot",
      "observed_record_scope": "all_received_records_including_unknown",
      "terminal_statuses": [
        "succeeded",
        "failed",
        "cancelled",
        "timed_out"
      ],
      "duplicate_policy": "open",
      "unknown_policy": "open",
      "failure_policy": "open",
      "partial_policy": "open",
      "complete_label_requires": [
        "expected_vs_represented",
        "no_duplicates",
        "no_unknown_identities",
        "terminal_status_accounted",
        "no_unresolved_identities"
      ]
    },
    "reductions": [
      {
        "name": "final_report_layer",
        "expected_identity_source": "route_launch_snapshot",
        "observed_result_source": "received_route_audit_result_records",
        "represented_identity_source": "route_identities_extracted_from_received_audit_results",
        "represented_identity_derivation": "from_observed_results",
        "status_count_source": "statuses_from_received_route_audit_results",
        "unresolved_identity_source": "expected_minus_observed_route_identities",
        "output_summary_identity_source": "emitted_final_report_manifest"
      }
    ],
    "final_reconciliation": {
      "expected_summary_identity_source": "emitted_final_report_manifest",
      "observed_summary_source": "received_final_report_records",
      "represented_identity_derivation": "from_observed_summaries",
      "checks": [
        "expected_vs_represented",
        "duplicate",
        "unknown",
        "terminal_status",
        "unresolved"
      ]
    }
  },
  "open_points": [
    {
      "key": "duplicate_policy",
      "question": "Do duplicate route audit result records block completion or get otherwise resolved during reconciliation?"
    },
    {
      "key": "unknown_policy",
      "question": "Do route audit result records for identities absent from the launch snapshot block completion or receive a separate tolerated classification?"
    },
    {
      "key": "failure_policy",
      "question": "Does any failed, cancelled, or timed_out route audit block final report completeness, or may synthesis proceed with an incomplete label?"
    },
    {
      "key": "partial_policy",
      "question": "If some expected route audits never produce observed records, must the workflow reject completion or may it emit an explicitly incomplete final report label?"
    }
  ],
  "scenarios": [
    {
      "kind": "positive",
      "expected": "complete_after_full_reconciliation"
    },
    {
      "kind": "missing",
      "expected": "missing_expected_identity_blocks_complete"
    },
    {
      "kind": "duplicate",
      "expected": "duplicate_blocks_complete"
    },
    {
      "kind": "failed",
      "expected": "failed_identity_blocks_complete"
    },
    {
      "kind": "timed_out",
      "expected": "timed_out_identity_blocks_complete"
    },
    {
      "kind": "unknown",
      "expected": "unknown_record_represented_excluded_from_join_blocks_complete"
    },
    {
      "kind": "partial_refused",
      "expected": "hypothetical_refusal_if_policy_rejects"
    },
    {
      "kind": "partial_allowed",
      "expected": "hypothetical_incomplete_label_if_policy_allows"
    }
  ],
  "boundary": {
    "control_plane": [
      "launch",
      "await",
      "accounting",
      "reconciliation",
      "control_plane_input_capacity"
    ],
    "target_data_plane": [
      "workers",
      "scheduling",
      "persistence",
      "rate_limiting",
      "backpressure"
    ]
  }
}
